// Normalize and validate financial data
const data = $input.item.json;

// Extract financial statements
const incomeStatement = data.income_statement || {};
const balanceSheet = data.balance_sheet || {};
const cashFlow = data.cash_flow || {};
const previous = data.previous_period || {};

const currentDate = new Date();
const reportMonth = currentDate.toLocaleString('en-US', { month: 'long', year: 'numeric' });
const reportId = `FRA-${currentDate.getFullYear()}-M${String(currentDate.getMonth() + 1).padStart(2, '0')}`;
const timestamp = currentDate.toISOString();

// --- P&L Metrics ---
const revenue = incomeStatement.total_revenue || 0;
const costOfRevenue = incomeStatement.cost_of_revenue || 0;
const grossProfit = revenue - costOfRevenue;
const grossMargin = revenue > 0 ? (grossProfit / revenue * 100) : 0;
const operatingExpenses = incomeStatement.operating_expenses || 0;
const operatingIncome = grossProfit - operatingExpenses;
const operatingMargin = revenue > 0 ? (operatingIncome / revenue * 100) : 0;
const netIncome = incomeStatement.net_income || 0;
const netMargin = revenue > 0 ? (netIncome / revenue * 100) : 0;
const ebitda = incomeStatement.ebitda || operatingIncome + (incomeStatement.depreciation || 0);

// --- Balance Sheet Metrics ---
const totalAssets = balanceSheet.total_assets || 0;
const totalLiabilities = balanceSheet.total_liabilities || 0;
const totalEquity = balanceSheet.total_equity || 0;
const currentAssets = balanceSheet.current_assets || 0;
const currentLiabilities = balanceSheet.current_liabilities || 0;
const cashAndEquivalents = balanceSheet.cash || 0;
const accountsReceivable = balanceSheet.accounts_receivable || 0;
const inventory = balanceSheet.inventory || 0;
const fixedAssets = balanceSheet.fixed_assets || 0;
const longTermDebt = balanceSheet.long_term_debt || 0;

// --- Cash Flow Metrics ---
const operatingCashFlow = cashFlow.operating_cash_flow || 0;
const investingCashFlow = cashFlow.investing_cash_flow || 0;
const financingCashFlow = cashFlow.financing_cash_flow || 0;
const freeCashFlow = operatingCashFlow - (cashFlow.capital_expenditures || 0);

// --- Financial Ratios ---
const currentRatio = currentLiabilities > 0 ? (currentAssets / currentLiabilities).toFixed(2) : 'N/A';
const quickRatio = currentLiabilities > 0 ? ((currentAssets - inventory) / currentLiabilities).toFixed(2) : 'N/A';
const debtToEquity = totalEquity > 0 ? (totalLiabilities / totalEquity).toFixed(2) : 'N/A';
const debtToAssets = totalAssets > 0 ? (totalLiabilities / totalAssets * 100).toFixed(2) : 'N/A';
const returnOnAssets = totalAssets > 0 ? (netIncome / totalAssets * 100).toFixed(2) : 'N/A';
const returnOnEquity = totalEquity > 0 ? (netIncome / totalEquity * 100).toFixed(2) : 'N/A';
const assetTurnover = revenue > 0 && totalAssets > 0 ? (revenue / totalAssets).toFixed(2) : 'N/A';
const interestCoverage = incomeStatement.interest_expense > 0 ? (ebitda / incomeStatement.interest_expense).toFixed(2) : 'N/A';

// --- YoY/MoM Comparison ---
const prevRevenue = previous.revenue || revenue;
const prevNetIncome = previous.net_income || netIncome;
const prevTotalAssets = previous.total_assets || totalAssets;

const revenueChange = prevRevenue > 0 ? ((revenue - prevRevenue) / prevRevenue * 100).toFixed(2) : 0;
const incomeChange = prevNetIncome !== 0 ? ((netIncome - prevNetIncome) / Math.abs(prevNetIncome) * 100).toFixed(2) : 0;
const assetChange = prevTotalAssets > 0 ? ((totalAssets - prevTotalAssets) / prevTotalAssets * 100).toFixed(2) : 0;

// --- Working Capital & Cash Analysis ---
const workingCapital = currentAssets - currentLiabilities;
const cashConversionCycle = (accountsReceivable + inventory) > 0 ? Math.round((accountsReceivable + inventory) / (revenue / 365)) : 0;
const daysInventoryOutstanding = revenue > 0 ? Math.round((inventory / (costOfRevenue / 365))) : 0;
const daysReceivablesOutstanding = revenue > 0 ? Math.round((accountsReceivable / (revenue / 365))) : 0;
const freeCashFlowMargin = revenue > 0 ? (freeCashFlow / revenue * 100).toFixed(2) : 0;

// --- Financial Health Score (0-100) ---
let healthScore = 50; // Base score
if (currentRatio >= 1.5) healthScore += 10; // Good liquidity
if (debtToEquity < 1) healthScore += 10; // Healthy leverage
if (netMargin > 10) healthScore += 10; // Good profitability
if (freeCashFlow > 0) healthScore += 10; // Positive FCF
if (revenueChange > 5) healthScore += 5; // Revenue growth
if (returnOnEquity > 15) healthScore += 5; // Good ROE
if (currentRatio < 1) healthScore -= 15; // Poor liquidity
if (debtToEquity > 2) healthScore -= 15; // High leverage
if (netMargin < 0) healthScore -= 20; // Unprofitable
healthScore = Math.max(0, Math.min(100, healthScore));

// --- Health Category ---
let healthCategory = 'Excellent';
if (healthScore < 30) healthCategory = 'Critical';
else if (healthScore < 50) healthCategory = 'Poor';
else if (healthScore < 70) healthCategory = 'Fair';
else if (healthScore < 85) healthCategory = 'Good';

return {
  json: {
    // Report Identity
    reportId,
    reportMonth,
    timestamp,

    // P&L Statement
    revenue: Math.round(revenue),
    cost_of_revenue: Math.round(costOfRevenue),
    gross_profit: Math.round(grossProfit),
    gross_margin_percent: parseFloat(grossMargin.toFixed(2)),
    operating_expenses: Math.round(operatingExpenses),
    operating_income: Math.round(operatingIncome),
    operating_margin_percent: parseFloat(operatingMargin.toFixed(2)),
    ebitda: Math.round(ebitda),
    net_income: Math.round(netIncome),
    net_margin_percent: parseFloat(netMargin.toFixed(2)),

    // Balance Sheet
    total_assets: Math.round(totalAssets),
    total_liabilities: Math.round(totalLiabilities),
    total_equity: Math.round(totalEquity),
    current_assets: Math.round(currentAssets),
    current_liabilities: Math.round(currentLiabilities),
    cash_equivalents: Math.round(cashAndEquivalents),
    accounts_receivable: Math.round(accountsReceivable),
    inventory: Math.round(inventory),
    fixed_assets: Math.round(fixedAssets),
    long_term_debt: Math.round(longTermDebt),
    working_capital: Math.round(workingCapital),

    // Cash Flow
    operating_cash_flow: Math.round(operatingCashFlow),
    investing_cash_flow: Math.round(investingCashFlow),
    financing_cash_flow: Math.round(financingCashFlow),
    free_cash_flow: Math.round(freeCashFlow),
    free_cash_flow_margin_percent: parseFloat(freeCashFlowMargin),

    // Financial Ratios
    current_ratio: currentRatio,
    quick_ratio: quickRatio,
    debt_to_equity: debtToEquity,
    debt_to_assets_percent: debtToAssets,
    return_on_assets_percent: returnOnAssets,
    return_on_equity_percent: returnOnEquity,
    asset_turnover: assetTurnover,
    interest_coverage: interestCoverage,

    // Operational Metrics
    days_inventory_outstanding: daysInventoryOutstanding,
    days_receivables_outstanding: daysReceivablesOutstanding,
    cash_conversion_cycle_days: cashConversionCycle,

    // YoY/MoM Changes
    revenue_change_percent: parseFloat(revenueChange),
    net_income_change_percent: parseFloat(incomeChange),
    total_assets_change_percent: parseFloat(assetChange),

    // Health Score
    financial_health_score: healthScore,
    financial_health_category: healthCategory,

    // Original data
    original_data: data
  }
};

// Analyze financial trends and detect anomalies
const data = $input.item.json;

// --- Revenue Trend Analysis ---
const revenueTrend = data.revenue_change_percent > 5 ? 'Growing' 
  : data.revenue_change_percent > 0 ? 'Stable Growth' 
  : data.revenue_change_percent > -5 ? 'Minor Decline' 
  : 'Significant Decline';

const marginTrend = data.operating_margin_percent > 15 ? 'Healthy' 
  : data.operating_margin_percent > 5 ? 'Acceptable' 
  : data.operating_margin_percent > 0 ? 'Weak' 
  : 'Unprofitable';

// --- Anomaly Detection ---
const anomalies = [];
const warnings = [];
const recommendations = [];

// Liquidity anomalies
if (parseFloat(data.current_ratio) < 1) {
  anomalies.push('Critical: Current ratio below 1.0 indicates potential liquidity crisis');
  recommendations.push('Improve short-term liquidity by increasing current assets or reducing current liabilities');
}
if (parseFloat(data.current_ratio) < 1.5) {
  warnings.push('Low current ratio may indicate tight working capital management');
}
if (data.cash_equivalents < data.current_liabilities * 0.2) {
  warnings.push('Cash reserves are low relative to current liabilities');
}

// Profitability anomalies
if (data.net_margin_percent < 0) {
  anomalies.push('Critical: Company is unprofitable with negative net margin');
  recommendations.push('Review cost structure and operating expenses to achieve profitability');
}
if (data.net_margin_percent < 5 && data.revenue > 0) {
  warnings.push('Low net profit margin indicates thin profitability');
}
if (data.gross_margin_percent < 20) {
  warnings.push('Low gross margin suggests high cost of goods sold');
  recommendations.push('Analyze pricing strategy and COGS reduction opportunities');
}

// Leverage anomalies
if (parseFloat(data.debt_to_equity) > 2) {
  anomalies.push('Critical: Debt-to-equity ratio exceeds 2.0, high financial risk');
  recommendations.push('Consider debt reduction or equity injection to strengthen balance sheet');
}
if (parseFloat(data.debt_to_equity) > 1.5) {
  warnings.push('High leverage may limit financial flexibility');
}

// Cash flow anomalies
if (data.free_cash_flow < 0) {
  anomalies.push('Critical: Negative free cash flow unsustainable long-term');
  recommendations.push('Reduce capital expenditures or improve operating cash flow generation');
}
if (data.free_cash_flow < data.net_income * 0.5) {
  warnings.push('Free cash flow significantly lower than net income (quality of earnings concern)');
  recommendations.push('Investigate working capital changes and cash conversion efficiency');
}

// Growth vs. profitability
if (data.revenue_change_percent > 10 && data.net_income_change_percent < data.revenue_change_percent - 5) {
  warnings.push('Revenue growth outpacing profit growth indicates margin pressure');
  recommendations.push('Monitor cost control and operational efficiency during growth phase');
}

// ROE anomalies
if (parseFloat(data.return_on_equity_percent) < 10) {
  warnings.push('Return on equity below 10% suggests suboptimal capital efficiency');
}
if (parseFloat(data.return_on_equity_percent) > 30) {
  recommendations.push('Exceptional ROE - consider whether leverage is sustainable');
}

// Working capital issues
if (data.cash_conversion_cycle_days > 90) {
  warnings.push('Long cash conversion cycle indicates working capital pressure');
  recommendations.push('Improve inventory turnover or accelerate receivables collection');
}

// Asset utilization
if (parseFloat(data.asset_turnover) < 0.5) {
  warnings.push('Low asset turnover suggests inefficient use of assets');
  recommendations.push('Review asset base efficiency and consider divestments if needed');
}

// Interest coverage
if (data.interest_coverage !== 'N/A' && parseFloat(data.interest_coverage) < 2) {
  anomalies.push('Low interest coverage ratio (< 2.0) indicates debt service risk');
  recommendations.push('Prioritize debt reduction or EBITDA improvement');
}

// Revenue stability check
if (Math.abs(data.revenue_change_percent) > 20) {
  warnings.push('Large revenue variance from prior period warrants investigation');
}

// --- Key Strengths ---
const strengths = [];
if (parseFloat(data.current_ratio) > 2) strengths.push('Strong liquidity position');
if (data.net_margin_percent > 15) strengths.push('Excellent profit margins');
if (parseFloat(data.debt_to_equity) < 0.5) strengths.push('Conservative debt levels');
if (data.free_cash_flow > data.net_income) strengths.push('Strong cash generation');
if (data.revenue_change_percent > 10) strengths.push('Robust revenue growth');
if (parseFloat(data.return_on_equity_percent) > 20) strengths.push('Excellent return on equity');

// --- Performance Rating ---
let performanceRating = 'Average';
if (anomalies.length > 2) performanceRating = 'Poor';
else if (anomalies.length > 0 || warnings.length > 3) performanceRating = 'Below Average';
else if (warnings.length > 0) performanceRating = 'Average';
else if (strengths.length > 3) performanceRating = 'Strong';
else if (strengths.length > 5) performanceRating = 'Excellent';

return {
  json: {
    ...data,

    // Trend Analysis
    revenue_trend: revenueTrend,
    margin_trend: marginTrend,

    // Anomalies & Warnings
    critical_anomalies: anomalies,
    anomaly_count: anomalies.length,
    warnings: warnings,
    warning_count: warnings.length,

    // Recommendations
    strategic_recommendations: recommendations,

    // Strengths
    key_strengths: strengths,
    strength_count: strengths.length,

    // Overall Assessment
    performance_rating: performanceRating,
    analysis_timestamp: new Date().toISOString()
  }
};

// Extract AI insights from API response
const response = $input.item.json;
const data = $input.item.json.original_data || {};

let aiInsights = '';
if (response.choices && response.choices.length > 0) {
  aiInsights = response.choices[0].message.content;
}

const executiveSummary = `
FINANCIAL PERFORMANCE SUMMARY (${data.reportMonth}):

🎯 KEY METRICS:
- Total Revenue: $${(data.revenue / 1000000).toFixed(1)}M (${data.revenue_change_percent > 0 ? '+' : ''}${data.revenue_change_percent}% YoY)
- Net Income: $${(data.net_income / 1000000).toFixed(1)}M
- Operating Margin: ${data.operating_margin_percent.toFixed(1)}%
- Free Cash Flow: $${(data.free_cash_flow / 1000000).toFixed(1)}M
- Financial Health Score: ${data.financial_health_score}/100 (${data.financial_health_category})

📊 BALANCE SHEET STRENGTH:
- Current Ratio: ${data.current_ratio} (Liquidity)
- Debt-to-Equity: ${data.debt_to_equity} (Leverage)
- Return on Equity: ${data.return_on_equity_percent}%
- Working Capital: $${(data.working_capital / 1000000).toFixed(1)}M

🚨 CRITICAL ITEMS (${data.anomaly_count}):
${data.critical_anomalies.length > 0 ? data.critical_anomalies.map(a => '- ' + a).join('\n') : '- No critical anomalies detected'}

⚠️ WARNINGS (${data.warning_count}):
${data.warnings.length > 0 ? data.warnings.map(w => '- ' + w).join('\n') : '- No warnings'}

💪 STRENGTHS (${data.strength_count}):
${data.key_strengths.length > 0 ? data.key_strengths.map(s => '- ' + s).join('\n') : '- Standard performance'}

🎯 STRATEGIC RECOMMENDATIONS:
${data.strategic_recommendations.length > 0 ? data.strategic_recommendations.map(r => '- ' + r).join('\n') : '- No immediate actions required'}

🤖 AI ANALYSIS:
${aiInsights}
`;

return {
  json: {
    ...data,
    ai_insights: aiInsights,
    executive_summary: executiveSummary,
    summary_generated: true
  }
};

