parameters.jsCode:
// Log report completion and track statistics
const timestamp = new Date().toISOString();
const data = $input.item.json;

console.log(`✅ FINANCIAL REPORT GENERATED: ${data.reportId} | Month: ${data.reportMonth} | Revenue: $${(data.revenue/1000000).toFixed(1)}M | Health: ${data.financial_health_score}/100 | Status: ${data.performance_rating} | Time: ${timestamp}`);

// Aggregate statistics
const stats = $getWorkflowStaticData('global').stats || {
  total_reports_generated: 0,
  avg_revenue: 0,
  avg_net_margin: 0,
  avg_health_score: 0,
  critical_months: 0,
  excellent_months: 0,
  total_anomalies: 0,
  last_generated: null
};

stats.total_reports_generated++;
stats.avg_revenue = ((stats.avg_revenue * (stats.total_reports_generated - 1)) + data.revenue) / stats.total_reports_generated;
stats.avg_net_margin = ((stats.avg_net_margin * (stats.total_reports_generated - 1)) + data.net_margin_percent) / stats.total_reports_generated;
stats.avg_health_score = ((stats.avg_health_score * (stats.total_reports_generated - 1)) + data.financial_health_score) / stats.total_reports_generated;
if (data.financial_health_category === 'Critical') stats.critical_months++;
if (data.financial_health_category === 'Excellent') stats.excellent_months++;
stats.total_anomalies += data.anomaly_count;
stats.last_generated = timestamp;

$getWorkflowStaticData('global').stats = stats;

return {
  json: {
    success: true,
    report_id: data.reportId,
    month: data.reportMonth,
    revenue: data.revenue,
    health_score: data.financial_health_score,
    health_category: data.financial_health_category,
    performance_rating: data.performance_rating,
    anomalies: data.anomaly_count,
    warnings: data.warning_count,
    timestamp,
    cumulativeStats: stats
  }
};
